function setEncodingValue(){if("home"!==window.dataPage)return;let e=document.querySelector('form dropmenu[data-type="encoding"]'),t=e.querySelector(".op-list li.active").getAttribute("data-option"),n=e.querySelector("input.random");n.setAttribute("name","d"),"cypher"===t?n.value=getRandom(0,93):"scrypto"===t?n.value=getRandomString(4):n.removeAttribute("name")}setEncodingValue();